// Contact Section
const ContactSection = () => {
  const [formData, setFormData] = useState({ name: '', email: '', phone: '', service: '', message: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.name || !formData.phone || !formData.service) { toast.error('Por favor completa los campos requeridos'); return; }
    setIsSubmitting(true);
    try {
      const response = await axios.post(`${API}/contact`, formData);
      if (response.data.success) {
        toast.success('¡Mensaje enviado! Redirigiendo a WhatsApp...');
        setTimeout(() => window.open(response.data.whatsapp_url, '_blank'), 1000);
        setFormData({ name: '', email: '', phone: '', service: '', message: '' });
      }
    } catch (error) {
      const whatsappMessage = `Hola oxByte! Soy ${formData.name}. Teléfono: ${formData.phone}. Me interesa: ${formData.service}. ${formData.message}`;
      window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(whatsappMessage)}`, '_blank');
    } finally { setIsSubmitting(false); }
  };

  return (
    <section id="contacto" className="py-24 md:py-32 px-6 md:px-12 bg-[#0a0a0a]">
      <div className="max-w-7xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
          <div>
            <p className="text-sm font-mono tracking-widest uppercase text-indigo-400 mb-4">Contacto</p>
            <h2 className="text-4xl md:text-5xl font-bold tracking-tight text-white mb-6">¿Listo para comenzar?</h2>
            <p className="text-slate-400 mb-10 leading-relaxed">Contáctanos por WhatsApp o completa el formulario.</p>
            <div className="space-y-6">
              <a href={`https://wa.me/${WHATSAPP_NUMBER}`} target="_blank" rel="noopener noreferrer" className="flex items-center gap-4 glass rounded-xl p-4 hover:border-indigo-500/50 transition-colors">
                <div className="w-12 h-12 rounded-lg bg-emerald-600/20 flex items-center justify-center"><MessageCircle className="w-6 h-6 text-emerald-400" /></div>
                <div><p className="text-white font-medium">WhatsApp</p><p className="text-slate-400 text-sm">55 5984 0541</p></div>
              </a>
              <div className="flex items-center gap-4 glass rounded-xl p-4">
                <div className="w-12 h-12 rounded-lg bg-indigo-600/20 flex items-center justify-center"><MapPin className="w-6 h-6 text-indigo-400" /></div>
                <div><p className="text-white font-medium">Ubicación</p><p className="text-slate-400 text-sm">Ciudad de México y área metropolitana</p></div>
              </div>
              <div className="flex items-center gap-4 glass rounded-xl p-4">
                <div className="w-12 h-12 rounded-lg bg-cyan-600/20 flex items-center justify-center"><Clock className="w-6 h-6 text-cyan-400" /></div>
                <div><p className="text-white font-medium">Horario</p><p className="text-slate-400 text-sm">Lun - Sáb: 9:00 AM - 7:00 PM</p></div>
              </div>
            </div>
          </div>
          <div className="glass rounded-2xl p-8">
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="text-sm text-slate-400 mb-2 block">Nombre *</label>
                <Input placeholder="Tu nombre" value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} className="bg-slate-900/50 border-slate-700 text-white placeholder:text-slate-600" />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="text-sm text-slate-400 mb-2 block">Email</label>
                  <Input type="email" placeholder="tu@email.com" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} className="bg-slate-900/50 border-slate-700 text-white placeholder:text-slate-600" />
                </div>
                <div>
                  <label className="text-sm text-slate-400 mb-2 block">Teléfono *</label>
                  <Input placeholder="55 1234 5678" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} className="bg-slate-900/50 border-slate-700 text-white placeholder:text-slate-600" />
                </div>
              </div>
              <div>
                <label className="text-sm text-slate-400 mb-2 block">Servicio de interés *</label>
                <Select value={formData.service} onValueChange={(value) => setFormData({ ...formData, service: value })}>
                  <SelectTrigger className="bg-slate-900/50 border-slate-700 text-white"><SelectValue placeholder="Selecciona un servicio" /></SelectTrigger>
                  <SelectContent className="bg-slate-900 border-slate-700">
                    <SelectItem value="soporte">Soporte Técnico</SelectItem>
                    <SelectItem value="camaras">Cámaras de Seguridad</SelectItem>
                    <SelectItem value="redes">Redes y WiFi</SelectItem>
                    <SelectItem value="datos">Recuperación de Datos</SelectItem>
                    <SelectItem value="acceso">Control de Acceso</SelectItem>
                    <SelectItem value="otro">Otro</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <label className="text-sm text-slate-400 mb-2 block">Mensaje</label>
                <Textarea placeholder="Cuéntanos sobre tu problema..." value={formData.message} onChange={(e) => setFormData({ ...formData, message: e.target.value })} className="bg-slate-900/50 border-slate-700 text-white placeholder:text-slate-600 min-h-[120px]" />
              </div>
              <Button type="submit" disabled={isSubmitting} className="w-full bg-indigo-600 hover:bg-indigo-700 text-white neon-glow btn-glow rounded-full py-6 text-lg font-semibold">
                {isSubmitting ? 'Enviando...' : <><Send className="w-5 h-5 mr-2" />Enviar y abrir WhatsApp</>}
              </Button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
};

// AI Chatbot Component
const Chatbot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([{ role: 'assistant', content: '¡Hola! Soy el asistente virtual de oxByte. ¿En qué puedo ayudarte hoy?' }]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sessionId] = useState(() => `session-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`);

  const sendMessage = async () => {
    if (!inputMessage.trim() || isLoading) return;
    const userMessage = inputMessage.trim();
    setInputMessage('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);
    try {
      const response = await axios.post(`${API}/chat`, { session_id: sessionId, message: userMessage });
      setMessages(prev => [...prev, { role: 'assistant', content: response.data.response }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'assistant', content: 'Lo siento, hubo un problema. Contáctanos por WhatsApp al 55 5984 0541.' }]);
    } finally { setIsLoading(false); }
  };

  const handleKeyPress = (e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); } };

  return (
    <>
      <button onClick={() => setIsOpen(!isOpen)} className="fixed bottom-6 right-6 w-14 h-14 rounded-full bg-indigo-600 text-white shadow-lg flex items-center justify-center cursor-pointer hover:bg-indigo-700 transition-colors neon-glow pulse-ring" style={{ zIndex: 9999 }}>
        {isOpen ? <X className="w-6 h-6" /> : <MessageCircle className="w-6 h-6" />}
      </button>
      {isOpen && (
        <div className="fixed bottom-24 right-6 w-[350px] h-[500px] glass rounded-2xl shadow-2xl flex flex-col overflow-hidden" style={{ zIndex: 9998 }}>
          <div className="bg-indigo-600/20 p-4 border-b border-white/10">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-indigo-600 flex items-center justify-center"><MessageCircle className="w-5 h-5 text-white" /></div>
              <div><p className="text-white font-semibold text-sm">Asistente oxByte</p><p className="text-emerald-400 text-xs flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-emerald-400"></span>En línea</p></div>
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] rounded-2xl px-4 py-2 text-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-br-md' : 'bg-slate-800 text-slate-200 rounded-bl-md'}`}>{msg.content}</div>
              </div>
            ))}
            {isLoading && <div className="flex justify-start"><div className="bg-slate-800 text-slate-200 rounded-2xl rounded-bl-md px-4 py-2 text-sm"><span className="flex gap-1"><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></span><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></span></span></div></div>}
          </div>
          <div className="p-4 border-t border-white/10">
            <div className="flex gap-2">
              <Input placeholder="Escribe tu mensaje..." value={inputMessage} onChange={(e) => setInputMessage(e.target.value)} onKeyPress={handleKeyPress} className="flex-1 bg-slate-900/50 border-slate-700 text-white placeholder:text-slate-500 text-sm" />
              <Button onClick={sendMessage} disabled={isLoading || !inputMessage.trim()} className="bg-indigo-600 hover:bg-indigo-700 text-white px-3"><Send className="w-4 h-4" /></Button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

